import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { UserLiveFeedParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/UserLiveFeedParser';

export class UserLiveFeedEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, UserLiveFeedParser);
    }

    public getParser(): UserLiveFeedParser {
        return this.parser as UserLiveFeedParser;
    }
}